    #[test]
    fn test_parse_migration_version() {
        assert_eq!(parse_migration_version("001_initial.sql"), Some(1));
        assert_eq!(parse_migration_version("002_add_users.sql"), Some(2));
        assert_eq!(parse_migration_version("010_big_update.sql"), Some(10));
        assert_eq!(parse_migration_version("invalid.sql"), None);
    }
